std::string normalizeURL(std::string url) {
    if (url.empty() || url.size() > 300) {
        return url;
    }

    // Check if protocol exists and convert to lowercase
    size_t protocolEnd = url.find("://");
    if (protocolEnd != std::string::npos) {
        std::string protocol = url.substr(0, protocolEnd);
        std::transform(protocol.begin(), protocol.end(), protocol.begin(), ::tolower);
        url = protocol + url.substr(protocolEnd);
    } else if (url.find('/') != std::string::npos || url.find('.') != std::string::npos) {
        // Prepend http:// if no protocol but has path or domain
        url = "http://" + url;
    }

    // Handle parameters
    size_t paramStart = url.find('?');
    if (paramStart != std::string::npos && paramStart + 1 < url.size()) {
        std::string base = url.substr(0, paramStart + 1);
        std::string paramsStr = url.substr(paramStart + 1);

        std::vector<std::string> params;
        std::istringstream iss(paramsStr);
        std::string param;
        while (std::getline(iss, param, '&')) {
            params.push_back(param);
        }

        std::sort(params.begin(), params.end());

        std::string newParams;
        for (size_t i = 0; i < params.size(); ++i) {
            if (i != 0) {
                newParams += "&";
            }
            newParams += params[i];
        }

        url = base + newParams;
    }

    return url;
}
