import java.util.*;

public class GraphUtils {
    public static int countConnectedComponents(Graph graph) {
        if (graph == null || graph.getVertices().isEmpty()) {
            return 0;
        }

        Set<Integer> visited = new HashSet<>();
        int count = 0;

        for (Integer vertex : graph.getVertices()) {
            if (!visited.contains(vertex)) {
                dfs(graph, vertex, visited);
                count++;
            }
        }

        return count;
    }

    private static void dfs(Graph graph, Integer vertex, Set<Integer> visited) {
        Stack<Integer> stack = new Stack<>();
        stack.push(vertex);
        visited.add(vertex);

        while (!stack.isEmpty()) {
            Integer current = stack.pop();
            for (Integer neighbor : graph.getNeighbors(current)) {
                if (!visited.contains(neighbor)) {
                    visited.add(neighbor);
                    stack.push(neighbor);
                }
            }
        }
    }
}

// Assume the Graph class has the following methods:
// Set<Integer> getVertices() - returns all vertices in the graph
// List<Integer> getNeighbors(Integer vertex) - returns neighbors of the given vertex
